from collections import deque
from typing import Optional

class Solution:
    def isCompleteTree(self, root: Optional[TreeNode]) -> bool:
        if not root:
            return True

        queue = deque([root])
        end = False

        while queue:
            node = queue.popleft()

            if node.left:
                if end:
                    return False
                queue.append(node.left)
            else:
                end = True

            if node.right:
                if end:
                    return False
                queue.append(node.right)
            else:
                end = True

        return True
```

This solution uses a level-order traversal (BFS) to check if the tree is complete. It uses a queue to traverse the tree and a flag `end` to indicate if we have encountered a node that does not have both children. If we encounter any node after `end` is set that has a child, the tree is not complete.
